# Create a checksum for the backup
sub create_checksum {
    my ($archive) = @_;
    my $checksum_file = "${archive}.sha256";

    print "[INFO] Generating SHA256 checksum...\n";

    # Try sha256sum first, fall back to shasum
    my $checksum_cmd;
    my $sha256sum_check = `which sha256sum 2>/dev/null`;
