# Rotate old backups (keep last N backups)
sub rotate_backups {
    my ($max_backups) = @_;
    $max_backups //= 5;

    print "[INFO] Checking for old backups to rotate (keeping last $max_backups)...\n";

    my @backups = sort glob("${backup_dir}/${basename}_backup_*.tar.gz");
    my $total = scalar @backups;

    if ($total > $max_backups) {
        my $to_remove = $total - $max_backups;
        print "[INFO] Found $total backups, removing $to_remove oldest...\n";

        for my $i (0 .. $to_remove - 1) {
            my $old_backup = $backups[$i];
            print "[INFO] Removing old backup: $old_backup\n";
            unlink $old_backup or warn "[WARN] Could not remove '$old_backup': $!\n";

